import base64
import zlib
import logging
from lxml import etree
from datetime import datetime, timezone

logger = logging.getLogger(__name__)

SAML_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

SAML_NAMESPACES = {
    'samlp': SAML_PROTOCOL_NS,
    'saml': SAML_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}

SAML_RESPONSE_SCHEMA = '''<?xml version="1.0" encoding="UTF-8"?>
<xs:schema xmlns:xs="http://www.w3.org/2001/XMLSchema"
           xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
           xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
           targetNamespace="urn:oasis:names:tc:SAML:2.0:protocol"
           elementFormDefault="qualified">

    <xs:import namespace="urn:oasis:names:tc:SAML:2.0:assertion"/>

    <xs:element name="Response">
        <xs:complexType>
            <xs:sequence>
                <xs:any processContents="lax" minOccurs="0" maxOccurs="unbounded"/>
            </xs:sequence>
            <xs:attribute name="ID" type="xs:string" use="required"/>
            <xs:attribute name="Version" type="xs:string" use="required"/>
            <xs:attribute name="IssueInstant" type="xs:string" use="required"/>
            <xs:anyAttribute processContents="lax"/>
        </xs:complexType>
    </xs:element>
</xs:schema>'''


class SAMLXMLValidationError(Exception):
    """Raised when SAML XML validation fails."""
    pass


class SAMLXMLValidator:
    """Validates SAML XML response structure and content."""

    def __init__(self):
        self.errors = []

    def decode_saml_response(self, encoded_response):
        """Decode base64-encoded SAML response."""
        try:
            decoded = base64.b64decode(encoded_response)
            try:
                decoded = zlib.decompress(decoded, -15)
            except zlib.error:
                pass
            return decoded
        except Exception as e:
            raise SAMLXMLValidationError(f"Failed to decode SAML response: {e}")

    def parse_xml(self, xml_bytes):
        """Parse XML bytes into an lxml Element, with security restrictions."""
        try:
            parser = etree.XMLParser(
                resolve_entities=False,
                no_network=True,
                dtd_validation=False,
                load_dtd=False,
                huge_tree=False,
            )
            root = etree.fromstring(xml_bytes, parser=parser)
            return root
        except etree.XMLSyntaxError as e:
            raise SAMLXMLValidationError(f"Invalid XML syntax: {e}")

    def validate_structure(self, root):
        """Validate the basic SAML Response structure."""
        self.errors = []

        # Check root element
        expected_tag = f'{{{SAML_PROTOCOL_NS}}}Response'
        if root.tag != expected_tag:
            self.errors.append(
                f"Root element must be samlp:Response, got {root.tag}"
            )
            raise SAMLXMLValidationError(
                f"Invalid root element: {root.tag}. Expected samlp:Response."
            )

        # Check required attributes
        required_attrs = ['ID', 'Version', 'IssueInstant']
        for attr in required_attrs:
            if root.get(attr) is None:
                self.errors.append(f"Missing required attribute: {attr}")

        # Check Version
        version = root.get('Version')
        if version and version != '2.0':
            self.errors.append(f"Unsupported SAML version: {version}. Expected 2.0.")

        # Check for Status element
        status = root.find('samlp:Status', SAML_NAMESPACES)
        if status is None:
            self.errors.append("Missing Status element")
        else:
            status_code = status.find('samlp:StatusCode', SAML_NAMESPACES)
            if status_code is None:
                self.errors.append("Missing StatusCode element")
            else:
                status_value = status_code.get('Value', '')
                if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
                    status_message_el = status.find('samlp:StatusMessage', SAML_NAMESPACES)
                    status_message = ''
                    if status_message_el is not None and status_message_el.text:
                        status_message = status_message_el.text
                    self.errors.append(
                        f"SAML authentication failed. Status: {status_value}. "
                        f"Message: {status_message}"
                    )

        # Check for Assertion
        assertion = root.find('saml:Assertion', SAML_NAMESPACES)
        if assertion is None:
            encrypted_assertion = root.find(
                'saml:EncryptedAssertion', SAML_NAMESPACES
            )
            if encrypted_assertion is not None:
                self.errors.append(
                    "EncryptedAssertion found but decryption is not supported "
                    "in this basic implementation."
                )
            else:
                self.errors.append("Missing Assertion element")
        else:
            self._validate_assertion(assertion)

        if self.errors:
            raise SAMLXMLValidationError(
                "SAML Response validation failed: " + "; ".join(self.errors)
            )

        return True

    def _validate_assertion(self, assertion):
        """Validate the Assertion element structure."""
        # Check Assertion ID
        if not assertion.get('ID'):
            self.errors.append("Assertion missing ID attribute")

        # Check Issuer
        issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is None:
            self.errors.append("Assertion missing Issuer element")

        # Check Subject
        subject = assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            self.errors.append("Assertion missing Subject element")
        else:
            name_id = subject.find('saml:NameID', SAML_NAMESPACES)
            if name_id is None:
                self.errors.append("Subject missing NameID element")

        # Check Conditions
        conditions = assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is not None:
            self._validate_conditions(conditions)

        # Check AuthnStatement
        authn_statement = assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is None:
            logger.warning("Assertion missing AuthnStatement element")

    def _validate_conditions(self, conditions):
        """Validate time conditions."""
        now = datetime.now(timezone.utc)

        not_before = conditions.get('NotBefore')
        if not_before:
            try:
                not_before_dt = datetime.fromisoformat(
                    not_before.replace('Z', '+00:00')
                )
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < not_before_dt - timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion not yet valid. NotBefore: {not_before}"
                    )
            except ValueError:
                self.errors.append(f"Invalid NotBefore datetime format: {not_before}")

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            try:
                not_on_or_after_dt = datetime.fromisoformat(
                    not_on_or_after.replace('Z', '+00:00')
                )
                from datetime import timedelta
                if now >= not_on_or_after_dt + timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion has expired. NotOnOrAfter: {not_on_or_after}"
                    )
            except ValueError:
                self.errors.append(
                    f"Invalid NotOnOrAfter datetime format: {not_on_or_after}"
                )

    def check_for_xml_attacks(self, xml_bytes):
        """Check for common XML-based attacks."""
        xml_str = xml_bytes if isinstance(xml_bytes, str) else xml_bytes.decode('utf-8', errors='ignore')

        # Check for entity declarations (XXE)
        if '<!ENTITY' in xml_str.upper():
            raise SAMLXMLValidationError(
                "XML entity declarations detected. Possible XXE attack."
            )

        # Check for DOCTYPE
        if '<!DOCTYPE' in xml_str.upper():
            raise SAMLXMLValidationError(
                "DOCTYPE declaration detected. Possible XXE attack."
            )

        # Check for XInclude
        if 'http://www.w3.org/2001/XInclude' in xml_str:
            raise SAMLXMLValidationError(
                "XInclude namespace detected. Possible XML injection."
            )

        # Check for XSLT
        if 'http://www.w3.org/1999/XSL/Transform' in xml_str:
            raise SAMLXMLValidationError(
                "XSLT namespace detected. Possible XML injection."
            )

        return True


