import logging
from lxml import etree
from .xml_validator import (
    SAMLXMLValidator,
    SAMLXMLValidationError,
    SAML_NAMESPACES,
    SAML_ASSERTION_NS,
)

logger = logging.getLogger(__name__)


class SAMLResponseParser:
    """Parses SAML Response XML to extract user information."""

    def __init__(self, xml_root):
        self.root = xml_root
        self.assertion = None
        self._find_assertion()

    def _find_assertion(self):
        """Find the Assertion element in the response."""
        self.assertion = self.root.find('saml:Assertion', SAML_NAMESPACES)
        if self.assertion is None:
            raise SAMLXMLValidationError("No Assertion found in SAML Response")

    def get_issuer(self):
        """Get the Issuer from the Response."""
        issuer = self.root.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is not None and issuer.text:
            return issuer.text.strip()

        issuer = self.assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is not None and issuer.text:
            return issuer.text.strip()

        return None

    def get_name_id(self):
        """Extract NameID from the assertion Subject."""
        subject = self.assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            raise SAMLXMLValidationError("No Subject found in Assertion")

        name_id_el = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id_el is None:
            raise SAMLXMLValidationError("No NameID found in Subject")

        return {
            'value': name_id_el.text.strip() if name_id_el.text else '',
            'format': name_id_el.get('Format', ''),
            'sp_name_qualifier': name_id_el.get('SPNameQualifier', ''),
            'name_qualifier': name_id_el.get('NameQualifier', ''),
        }

    def get_session_index(self):
        """Get the SessionIndex from AuthnStatement."""
        authn_statement = self.assertion.find(
            'saml:AuthnStatement', SAML_NAMESPACES
        )
        if authn_statement is not None:
            return authn_statement.get('SessionIndex', '')
        return ''

    def get_attributes(self):
        """Extract all attributes from the assertion's AttributeStatement."""
        attributes = {}

        attr_statement = self.assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attr_statement is None:
            logger.warning("No AttributeStatement found in Assertion")
            return attributes

        for attr_el in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attr_el.get('Name', '')
            attr_friendly_name = attr_el.get('FriendlyName', '')

            values = []
            for value_el in attr_el.findall('saml:AttributeValue', SAML_NAMESPACES):
                if value_el.text:
                    values.append(value_el.text.strip())
                else:
                    # Check for nested XML elements (e.g., complex attribute values)
                    children = list(value_el)
                    if children:
                        values.append(etree.tostring(value_el, encoding='unicode'))
                    else:
                        values.append('')

            # Store by both Name and FriendlyName for flexible lookup
            if attr_name:
                attributes[attr_name] = values
            if attr_friendly_name and attr_friendly_name != attr_name:
                attributes[attr_friendly_name] = values

        return attributes

    def get_conditions(self):
        """Extract conditions from the assertion."""
        conditions_el = self.assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions_el is None:
            return {}

        conditions = {
            'not_before': conditions_el.get('NotBefore', ''),
            'not_on_or_after': conditions_el.get('NotOnOrAfter', ''),
            'audiences': [],
        }

        for audience_restriction in conditions_el.findall(
            'saml:AudienceRestriction', SAML_NAMESPACES
        ):
            for audience in audience_restriction.findall(
                'saml:Audience', SAML_NAMESPACES
            ):
                if audience.text:
                    conditions['audiences'].append(audience.text.strip())

        return conditions

    def extract_user_info(self, attribute_mapping):
        """
        Extract user information based on attribute mapping configuration.

        attribute_mapping is a dict like:
        {
            'email': ['http://schemas.xmlsoap.org/...', 'email', 'Email'],
            'first_name': ['http://schemas.xmlsoap.org/...', 'givenName'],
            ...
        }
        """
        raw_attributes = self.get_attributes()
        user_info = {}

        for field_name, possible_attr_names in attribute_mapping.items():
            for attr_name in possible_attr_names:
                if attr_name in raw_attributes:
                    values = raw_attributes[attr_name]
                    if field_name == 'groups':
                        user_info[field_name] = values
                    else:
                        user_info[field_name] = values[0] if values else ''
                    break

        return user_info

    def get_full_response_data(self, attribute_mapping=None):
        """Get all parsed data from the SAML response."""
        name_id_data = self.get_name_id()
        raw_attributes = self.get_attributes()

        data = {
            'issuer': self.get_issuer(),
            'name_id': name_id_data['value'],
            'name_id_format': name_id_data['format'],
            'session_index': self.get_session_index(),
            'raw_attributes': raw_attributes,
            'conditions': self.get_conditions(),
        }

        if attribute_mapping:
            data['user_info'] = self.extract_user_info(attribute_mapping)

        return data


# saml_sp/auth_backend.py
import logging
from django.conf import settings
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import BaseBackend

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthBackend(BaseBackend):
    """Django authentication backend for SAML SSO."""

    def authenticate(self, request, saml_data=None, **kwargs):
        if saml_data is None:
            return None

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        create_unknown = saml_settings.get('create_unknown_user', True)
        update_on_login = saml_settings.get('update_user_on_login', True)

        name_id = saml_data.get('name_id', '')
        user_info = saml_data.get('user_info', {})

        if not name_id:
            logger.error("No NameID in SAML data")
            return None

        email = user_info.get('email', name_id)

        try:
            # Try to find existing user
            try:
                user = User.objects.get(email=email)
            except User.DoesNotExist:
                try:
                    user = User.objects.get(username=name_id)
                except User.DoesNotExist:
                    user = None

            if user is None:
                if not create_unknown:
                    logger.warning(
                        f"User not found for NameID {name_id} and "
                        f"create_unknown_user is False"
                    )
                    return None

                user = self._create_user(name_id, email, user_info)
                logger.info(f"Created new user from SAML: {user.username}")
            elif update_on_login:
                user = self._update_user(user, user_info)
                logger.info(f"Updated user from SAML: {user.username}")

            if not user.is_active:
                logger.warning(f"User {user.username} is inactive")
                return None

            return user

        except Exception as e:
            logger.exception(f"Error during SAML authentication: {e}")
            return None

    def _create_user(self, name_id, email, user_info):
        """Create a new Django user from SAML data."""
        username = self._generate_username(name_id, email)

        user = User(
            username=username,
            email=email,
            first_name=user_info.get('first_name', '')[:150],
            last_name=user_info.get('last_name', '')[:150],
            is_active=True,
        )
        user.set_unusable_password()
        user.save()

        self._update_groups(user, user_info.get('groups', []))

        return user

    def _update_user(self, user, user_info):
        """Update existing user with SAML attributes."""
        changed = False

        if 'email' in user_info and user_info['email'] and user.email != user_info['email']:
            user.email = user_info['email']
            changed = True

        if 'first_name' in user_info and user.first_name != user_info['first_name'][:150]:
            user.first_name = user_info['first_name'][:150]
            changed = True

        if 'last_name' in user_info and user.last_name != user_info['last_name'][:150]:
            user.last_name = user_info['last_name'][:150]
            changed = True

        if changed:
            user.save()

        self._update_groups(user, user_info.get('groups', []))

        return user

    def _update_groups(self, user, group_names):
        """Update user's group memberships based on SAML groups."""
        if not group_names:
            return

        from django.contrib.auth.models import Group

        groups = []
        for group_name in group_names:
            group, _ = Group.objects.get_or_create(name=group_name)
            groups.append(group)

        user.groups.set(groups)

    def _generate_username(self, name_id, email):
        """Generate a unique username."""
        # Prefer email username part, fall back to name_id
        if '@' in email:
            base_username = email.split('@')[0]
        else:
            base_username = name_id

        # Sanitize
        base_username = ''.join(
            c for c in base_username if c.isalnum() or c in '._-'
        )[:140]

        username = base_username
        counter = 1
        while User.objects.filter(username=username).exists():
            username = f"{base_username}_{counter}"
            counter += 1

        return username

    def get_user(self, user_id):
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None


