import logging
import uuid
from datetime import datetime, timezone
from urllib.parse import urlencode

from django.conf import settings
from django.contrib import auth
from django.http import HttpResponse, HttpResponseBadRequest, HttpResponseRedirect
from django.urls import reverse
from django.utils.decorators import method_decorator
from django.views import View
from django.views.decorators.csrf import csrf_exempt
from django.views.decorators.cache import never_cache

from .models import SAMLSession
from .saml_parser import SAMLResponseParser
from .xml_validator import SAMLXMLValidator, SAMLXMLValidationError

logger = logging.getLogger(__name__)


def get_saml_settings():
    return getattr(settings, 'SAML_SP_SETTINGS', {})


class SAMLLoginView(View):
    """Initiates SAML SSO by redirecting to IdP."""

    def get(self, request):
        saml_settings = get_saml_settings()
        idp_sso_url = saml_settings.get('idp_sso_url')

        if not idp_sso_url:
            return HttpResponseBadRequest("SAML IdP SSO URL not configured")

        # Store relay state (return URL)
        relay_state = request.GET.get('next', '/')
        request.session['saml_relay_state'] = relay_state

        # Generate AuthnRequest ID
        request_id = f"_id-{uuid.uuid4()}"
        request.session['saml_request_id'] = request_id

        # Build AuthnRequest
        authn_request = self._build_authn_request(saml_settings, request_id)

        import base64
        encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')

        # Redirect to IdP with POST binding parameters
        params = {
            'SAMLRequest': encoded_request,
            'RelayState': relay_state,
        }

        redirect_url = f"{idp_sso_url}?{urlencode(params)}"
        return HttpResponseRedirect(redirect_url)

    def _build_authn_request(self, saml_settings, request_id):
        """Build a SAML AuthnRequest XML."""
        now = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')
        idp_entity_id = saml_settings.get('idp_entity_id', '')

        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{now}"
    Destination="{saml_settings.get('idp_sso_url', '')}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

        return authn_request


@method_decorator(csrf_exempt, name='dispatch')
@method_decorator(never_cache, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service - handles SAML POST responses from IdP.
    """

    def post(self, request):
        saml_response_encoded = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')

        if not saml_response_encoded:
            logger.error("No SAMLResponse in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse parameter")

        try:
            # Step 1: Decode and validate XML
            validator = SAMLXMLValidator()

            xml_bytes = validator.decode_saml_response(saml_response_encoded)
            validator.check_for_xml_attacks(xml_bytes)
            root = validator.parse_xml(xml_bytes)
            validator.validate_structure(root)

            # Step 2: Parse SAML response
            parser = SAMLResponseParser(root)
            saml_settings = get_saml_settings()
            attribute_mapping = saml_settings.get('attribute_mapping', {})

            response_data = parser.get_full_response_data(attribute_mapping)

            # Step 3: Validate issuer
            expected_issuer = saml_settings.get('idp_entity_id')
            if expected_issuer and response_data['issuer'] != expected_issuer:
                logger.error(
                    f"Issuer mismatch. Expected: {expected_issuer}, "
                    f"Got: {response_data['issuer']}"
                )
                return HttpResponseBadRequest("Invalid SAML Response issuer")

            # Step 4: Validate audience
            conditions = response_data.get('conditions', {})
            audiences = conditions.get('audiences', [])
            entity_id = saml_settings.get('entity_id')
            if audiences and entity_id and entity_id not in audiences:
                logger.error(
                    f"Audience mismatch. Expected: {entity_id}, "
                    f"Got: {audiences}"
                )
                return HttpResponseBadRequest("Invalid audience in SAML Response")

            # Step 5: Authenticate user
            user = auth.authenticate(request, saml_data=response_data)

            if user is None:
                logger.error("SAML authentication failed - no user returned")
                return HttpResponseBadRequest(
                    "Authentication failed. Unable to authenticate user."
                )

            # Step 6: Login user and create session
            auth.login(request, user, backend='saml_sp.auth_backend.SAMLAuthBackend')

            # Step 7: Store SAML session data
            self._create_saml_session(request, user, response_data)

            logger.info(
                f"SAML SSO login successful for user: {user.username} "
                f"(NameID: {response_data['name_id']})"
            )

            # Step 8: Redirect to relay state
            if not relay_state or not relay_state.startswith('/'):
                relay_state = '/'

            return HttpResponseRedirect(relay_state)

        except SAMLXMLValidationError as e:
            logger.error(f"SAML validation error: {e}")
            return HttpResponseBadRequest(f"SAML Response validation failed: {e}")
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {e}")
            return HttpResponseBadRequest("Error processing SAML response")

    def _create_saml_session(self, request, user, response_data):
        """Create a SAMLSession record for tracking."""
        from datetime import datetime, timezone

        expires_at = None
        conditions = response_data.get('conditions', {})
        not_on_or_after = conditions.get('not_on_or_after')
        if not_on_or_after:
            try:
                expires_at = datetime.fromisoformat(
                    not_on_or_after.replace('Z', '+00:00')
                )
            except ValueError:
                pass

        # Serialize attributes for JSON storage
        raw_attributes = response_data.get('raw_attributes', {})

        SAMLSession.objects.create(
            user=user,
            session_key=request.session.session_key or '',
            name_id=response_data.get('name_id', ''),
            name_id_format=response_data.get('name_id_format', ''),
            session_index=response_data.get('session_index', ''),
            attributes=raw_attributes,
            expires_at=expires_at,
        )


class SAMLLogoutView(View):
    """Handle SAML logout."""

    def get(self, request):
        return self._logout(request)

    def post(self, request):
        return self._logout(request)

    def _logout(self, request):
        if request.user.is_authenticated:
            # Clean up SAML sessions
            session_key = request.session.session_key
            if session_key:
                SAMLSession.objects.filter(
                    user=request.user,
                    session_key=session_key
                ).delete()

            logger.info(f"SAML logout for user: {request.user.username}")

        auth.logout(request)

        logout_redirect = getattr(settings, 'LOGOUT_REDIRECT_URL', '/')
        return HttpResponseRedirect(logout_redirect)


class SAMLMetadataView(View):
    """Serve SP metadata XML."""

    def get(self, request):
        saml_settings = get_saml_settings()
        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')

        metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

        return HttpResponse(metadata, content_type='application/xml')


