# saml_sp/middleware.py
import logging
from datetime import datetime, timezone

from django.conf import settings
from django.contrib import auth
from django.utils.deprecation import MiddlewareMixin

from .models import SAMLSession

logger = logging.getLogger(__name__)


class SAMLSessionMiddleware(MiddlewareMixin):
    """
    Middleware to check SAML session validity.
    Logs out users whose SAML sessions have expired.
    """

    def process_request(self, request):
        if not request.user.is_authenticated:
            return None

        session_key = request.session.session_key
        if not session_key:
            return None

        try:
            saml_session = SAMLSession.objects.filter(
                user=request.user,
                session_key=session_key,
            ).order_by('-created_at').first()

            if saml_session is None:
                # User might have logged in via non-SAML method
                return None

            if saml_session.expires_at:
                now = datetime.now(timezone.utc)
                if now >= saml_session.expires_at:
                    logger.info(
                        f"SAML session expired for user {request.user.username}"
                    )
                    saml_session.delete()
                    auth.logout(request)

        except Exception as e:
            logger.exception(f"Error checking SAML session: {e}")

        return None


