SAML_SP_TEST_SETTINGS = {
    'entity_id': 'https://sp.example.com/saml/metadata/',
    'acs_url': 'https://sp.example.com/saml/acs/',
    'idp_entity_id': 'https://idp.example.com/',
    'idp_sso_url': 'https://idp.example.com/sso/',
    'idp_cert': '',
    'attribute_mapping': {
        'email': ['email', 'Email'],
        'first_name': ['firstName', 'givenName'],
        'last_name': ['lastName', 'sn'],
        'groups': ['groups', 'memberOf'],
    },
    'create_unknown_user': True,
    'update_user_on_login': True,
}


def build_saml_response(
    name_id='user@example.com',
    attributes=None,
    status='urn:oasis:names:tc:SAML:2.0:status:Success',
    issuer='https://idp.example.com/',
    audience='https://sp.example.com/saml/metadata/',
):
    now = datetime.now(timezone.utc)
    not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (now + timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')
    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')

    attr_xml = ''
    if attributes:
        attr_statements = []
        for name, values in attributes.items():
            values_xml = ''.join(
                f'<saml:AttributeValue>{v}</saml:AttributeValue>'
                for v in values
            )
            attr_statements.append(
                f'<saml:Attribute Name="{name}">{values_xml}</saml:Attribute>'
            )
        attr_xml = (
            '<saml:AttributeStatement>'
            + ''.join(attr_statements)
            + '</saml:AttributeStatement>'
        )

    response_xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="_response_123"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="https://sp.example.com/saml/acs/">
    <saml:Issuer>{issuer}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="{status}"/>
    </samlp:Status>
    <saml:Assertion ID="_assertion_456" Version="2.0" IssueInstant="{issue_instant}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    NotOnOrAfter="{not_on_or_after}"
                    Recipient="https://sp.example.com/saml/acs/"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{audience}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="_session_789">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:Password</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        {attr_xml}
    </saml:Assertion>
</samlp:Response>'''

    return response_xml


class SAMLXMLValidatorTest(TestCase):

    def setUp(self):
        self.validator = SAMLXMLValidator()

    def test_decode_saml_response(self):
        xml = '<test>hello</test>'
        encoded = base64.b64encode(xml.encode('utf-8')).decode('utf-8')
        decoded = self.validator.decode_saml_response(encoded)
        self.assertEqual(decoded, xml.encode('utf-8'))

    def test_parse_valid_xml(self):
        xml = b'<root><child/></root>'
        root = self.validator.parse_xml(xml)
        self.assertEqual(root.tag, 'root')

    def test_parse_invalid_xml(self):
        with self.assertRaises(SAMLXMLValidationError):
            self.validator.parse_xml(b'<not valid xml')

    def test_validate_structure_valid(self):
        xml = build_saml_response()
        root = self.validator.parse_xml(xml.encode('utf-8'))
        self.assertTrue(self.validator.validate_structure(root))

    def test_validate_structure_wrong_root(self):
        xml = b'<root xmlns="urn:oasis:names:tc:SAML:2.0:protocol"/>'
        root = self.validator.parse_xml(xml)
        with self.assertRaises(SAMLXMLValidationError):
            self.validator.validate_structure(root)

    def test_validate_structure_failed_status(self):
        xml = build_saml_response(
            status='urn:oasis:names:tc:SAML:2.0:status:Requester'
        )
        root = self.validator.parse_xml(xml.encode('utf-8'))
        with self.assertRaises(SAMLXMLValidationError):
            self.validator.validate_structure(root)

    def test_check_xxe_attack(self):
        xml = b'<!DOCTYPE foo [<!ENTITY xxe SYSTEM "file:///etc/passwd">]><root/>'
        with self.assertRaises(SAMLXMLValidationError):
            self.validator.check_for_xml_attacks(xml)

    def test_check_xinclude_attack(self):
        xml = b'<root xmlns:xi="http://www.w3.org/2001/XInclude"><xi:include/></root>'
        with self.assertRaises(SAMLXMLValidationError):
            self.validator.check_for_xml_attacks(xml)


class SAMLResponseParserTest(TestCase):

    def _get_parser(self, **kwargs):
        xml = build_saml_response(**kwargs)
        validator = SAMLXMLValidator()
        root = validator.parse_xml(xml.encode('utf-8'))
        return SAMLResponseParser(root)

    def test_get_name_id(self):
        parser = self._get_parser(name_id='john@example.com')
        name_id = parser.get_name_id()
        self.assertEqual(name_id['value'], 'john@example.com')
        self.assertIn('emailAddress', name_id['format'])

    def test_get_issuer(self):
        parser = self._get_parser(issuer='https://idp.test.com/')
        self.assertEqual(parser.get_issuer(), 'https://idp.test.com/')

    def test_get_session_index(self):
        parser = self._get_parser()
        self.assertEqual(parser.get_session_index(), '_session_789')

    def test_get_attributes(self):
        parser = self._get_parser(attributes={
            'email': ['john@example.com'],
            'firstName': ['John'],
            'lastName': ['Doe'],
            'groups': ['admin', 'users'],
        })
        attrs = parser.get_attributes()
        self.assertEqual(attrs['email'], ['john@example.com'])
        self.assertEqual(attrs['firstName'], ['John'])
        self.assertEqual(attrs['groups'], ['admin', 'users'])

    def test_extract_user_info(self):
        parser = self._get_parser(attributes={
            'email': ['john@example.com'],
            'firstName': ['John'],
            'lastName': ['Doe'],
            'groups': ['admin', 'users'],
        })
        mapping = SAML_SP_TEST_SETTINGS['attribute_mapping']
        user_info = parser.extract_user_info(mapping)
        self.assertEqual(user_info['email'], 'john@example.com')
        self.assertEqual(user_info['first_name'], 'John')
        self.assertEqual(user_info['last_name'], 'Doe')
        self.assertEqual(user_info['groups'], ['admin', 'users'])

    def test_get_conditions(self):
        parser = self._get_parser()
        conditions = parser.get_conditions()
        self.assertIn('not_before', conditions)
        self.assertIn('not_on_or_after', conditions)
        self.assertIn('https://sp.example.com/saml/metadata/', conditions['audiences'])

    def test_get_full_response_data(self):
        parser = self._get_parser(
            name_id='jane@example.com',
            attributes={'email': ['jane@example.com'], 'firstName': ['Jane']},
        )
        mapping = SAML_SP_TEST_SETTINGS['attribute_mapping']
        data = parser.get_full_response_data(mapping)
        self.assertEqual(data['name_id'], 'jane@example.com')
        self.assertEqual(data['user_info']['email'], 'jane@example.com')
        self.assertEqual(data['user_info']['first_name'], 'Jane')


