class SAMLAuthBackendTest(TestCase):

    def setUp(self):
        self.backend = SAMLAuthBackend()
        self.factory = RequestFactory()

    def test_authenticate_creates_user(self):
        request = self.factory.get('/')
        saml_data = {
            'name_id': 'newuser@example.com',
            'user_info': {
                'email': 'newuser@example.com',
                'first_name': 'New',
                'last_name': 'User',
            },
        }
        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNotNone(user)
        self.assertEqual(user.email, 'newuser@example.com')
        self.assertEqual(user.first_name, 'New')
        self.assertEqual(user.last_name, 'User')
        self.assertTrue(user.is_active)
        self.assertFalse(user.has_usable_password())

    def test_authenticate_existing_user(self):
        existing = User.objects.create_user(
            username='existing',
            email='existing@example.com',
            first_name='Old',
            last_name='Name',
        )
        request = self.factory.get('/')
        saml_data = {
            'name_id': 'existing@example.com',
            'user_info': {
                'email': 'existing@example.com',
                'first_name': 'Updated',
                'last_name': 'Name',
            },
        }
        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNotNone(user)
        self.assertEqual(user.pk, existing.pk)
        self.assertEqual(user.first_name, 'Updated')

    def test_authenticate_no_saml_data(self):
        request = self.factory.get('/')
        user = self.backend.authenticate(request)
        self.assertIsNone(user)

    def test_authenticate_no_name_id(self):
        request = self.factory.get('/')
        saml_data = {'name_id': '', 'user_info': {}}
        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNone(user)

    @override_settings(SAML_SP_SETTINGS={**SAML_SP_TEST_SETTINGS, 'create_unknown_user': False})
    def test_authenticate_no_create_unknown(self):
        request = self.factory.get('/')
        saml_data = {
            'name_id': 'unknown@example.com',
            'user_info': {'email': 'unknown@example.com'},
        }
        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNone(user)

    def test_authenticate_inactive_user(self):
        User.objects.create_user(
            username='inactive',
            email='inactive@example.com',
            is_active=False,
        )
        request = self.factory.get('/')
        saml_data = {
            'name_id': 'inactive@example.com',
            'user_info': {'email': 'inactive@example.com'},
        }
        user = self.backend.authenticate(request, saml_data=saml_data)
        self.assertIsNone(user)

    def test_get_user(self):
        user = User.objects.create_user(username='testuser', email='test@example.com')
        found = self.backend.get_user(user.pk)
        self.assertEqual(found, user)

    def test_get_user_not_found(self):
        found = self.backend.get_user(99999)
